<?php
namespace Tests\Feature\Hr;
use Illuminate\Support\Facades\Artisan; use Illuminate\Support\Facades\Schema; use Tests\TestCase;
class HrPhase3EIntegrationRollbackTest extends TestCase { use RefreshHrDatabase; public function test_integration_trace_schema_exists():void{$this->assertTrue(Schema::hasColumns('hr_integration_outbox',['legal_entity_id','target','source_key','payload_hash','status']));$this->assertTrue(Schema::hasColumns('hr_asset_assignments',['accepted_at','accepted_by','acceptance_ip','acceptance_statement_version']));$this->assertTrue(Schema::hasColumn('hr_assets','stock_item_reference'));} public function test_rollback_preserves_phase3d_tables():void{Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step' => 4]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>3]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>6]);Artisan::call('migrate:rollback',['--step'=>2]);$this->assertFalse(Schema::hasTable('hr_integration_outbox'));$this->assertTrue(Schema::hasTable('hr_assets'));$this->assertTrue(Schema::hasTable('hr_advances'));} }
